const CONFIG = {
  RPC_URL: process.env.ETH_RPC_URL || 'http://localhost:8545',
  CHAIN_ID: parseInt(process.env.CHAIN_ID || '1'),
  GAS_LIMIT_ETH_TRANSFER: 21000,
  GAS_LIMIT_CONTRACT_CALL: 200000,
  MAX_PRIORITY_FEE_GWEI: process.env.MAX_PRIORITY_FEE_GWEI || '2',
  MAX_FEE_GWEI: process.env.MAX_FEE_GWEI || '50',
};

// ============================================================
// Wallet Manager - Handles wallet creation and signing
// ============================================================
class WalletManager {
  constructor(provider) {
    this.provider = provider;
    this.wallets = new Map();
  }

  /**
   * Load a wallet from a private key stored in environment variables.
   * NEVER hardcode private keys in source code.
   * Use environment variables, secrets manager, or HSM in production.
   */
  loadWalletFromEnv(envVarName, walletLabel) {
    const privateKey = process.env[envVarName];
    if (!privateKey) {
      throw new Error(
        `Environment variable ${envVarName} is not set. ` +
        `Set it with: export ${envVarName}=0xYourPrivateKey`
      );
    }

    if (!privateKey.match(/^0x[0-9a-fA-F]{64}$/)) {
      throw new Error(`Invalid private key format in ${envVarName}`);
    }

    const wallet = new ethers.Wallet(privateKey, this.provider);
    this.wallets.set(walletLabel, wallet);

    console.log(`Wallet "${walletLabel}" loaded: ${wallet.address}`);
    return wallet;
  }

  getWallet(label) {
    const wallet = this.wallets.get(label);
    if (!wallet) {
      throw new Error(`Wallet "${label}" not found. Load it first.`);
    }
    return wallet;
  }

  async getBalance(label) {
    const wallet = this.getWallet(label);
    const balance = await this.provider.getBalance(wallet.address);
    return ethers.formatEther(balance);
  }

  async getNonce(label) {
    const wallet = this.getWallet(label);
    return await this.provider.getTransactionCount(wallet.address, 'latest');
  }
}

// ============================================================
// Transaction Service - Handles ETH transfers
// ============================================================
class TransactionService {
  constructor(provider, walletManager) {
    this.provider = provider;
    this.walletManager = walletManager;
  }

  /**
   * Send ETH from one wallet to a recipient address
   */
  async sendETH(walletLabel, toAddress, amountInEther, options = {}) {
    // Validate inputs
    if (!ethers.isAddress(toAddress)) {
      throw new Error(`Invalid recipient address: ${toAddress}`);
    }

    const amount = ethers.parseEther(amountInEther.toString());
    if (amount <= 0n) {
      throw new Error('Amount must be greater than 0');
    }

    const wallet = this.walletManager.getWallet(walletLabel);

    // Check balance
    const balance = await this.provider.getBalance(wallet.address);
    if (balance < amount) {
      throw new Error(
        `Insufficient balance. Have: ${ethers.formatEther(balance)} ETH, ` +
        `Need: ${amountInEther} ETH`
      );
    }

    // Build transaction
    const nonce = await this.provider.getTransactionCount(wallet.address, 'latest');
    const feeData = await this.provider.getFeeData();

    const tx = {
      to: toAddress,
      value: amount,
      nonce: nonce,
      gasLimit: options.gasLimit || CONFIG.GAS_LIMIT_ETH_TRANSFER,
      maxPriorityFeePerGas: options.maxPriorityFeePerGas ||
        feeData.maxPriorityFeePerGas ||
        ethers.parseUnits(CONFIG.MAX_PRIORITY_FEE_GWEI, 'gwei'),
      maxFeePerGas: options.maxFeePerGas ||
        feeData.maxFeePerGas ||
        ethers.parseUnits(CONFIG.MAX_FEE_GWEI, 'gwei'),
      chainId: CONFIG.CHAIN_ID,
      type: 2, // EIP-1559
    };

    console.log(`Sending ${amountInEther} ETH from ${wallet.address} to ${toAddress}...`);

    // Sign and send
    const txResponse = await wallet.sendTransaction(tx);
    console.log(`Transaction sent! Hash: ${txResponse.hash}`);

    // Wait for confirmation
    const receipt = await txResponse.wait(1);
    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);
    console.log(`Gas used: ${receipt.gasUsed.toString()}`);

    return {
      hash: txResponse.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
      from: wallet.address,
      to: toAddress,
      amount: amountInEther,
    };
  }

  /**
   * Send ETH to multiple recipients in sequence
   */
  async batchSendETH(walletLabel, recipients) {
    const results = [];
    for (const { address, amount } of recipients) {
      try {
        const result = await this.sendETH(walletLabel, address, amount);
        results.push({ ...result, error: null });
      } catch (error) {
        results.push({
          to: address,
          amount,
          status: 'failed',
          error: error.message,
        });
      }
    }
    return results;
  }
}

// ============================================================
// Contract Service - Handles smart contract interactions
// ============================================================
class ContractService {
  constructor(provider, walletManager) {
    this.provider = provider;
    this.walletManager = walletManager;
    this.contracts = new Map();
  }

  /**
   * Load a smart contract instance
   */
  loadContract(contractLabel, contractAddress, abi, walletLabel = null) {
    if (!ethers.isAddress(contractAddress)) {
      throw new Error(`Invalid contract address: ${contractAddress}`);
    }

    let signerOrProvider = this.provider;
    if (walletLabel) {
      signerOrProvider = this.walletManager.getWallet(walletLabel);
    }

    const contract = new ethers.Contract(contractAddress, abi, signerOrProvider);
    this.contracts.set(contractLabel, {
      contract,
      address: contractAddress,
      walletLabel,
    });

    console.log(`Contract "${contractLabel}" loaded at ${contractAddress}`);
    return contract;
  }

  getContract(label) {
    const entry = this.contracts.get(label);
    if (!entry) {
      throw new Error(`Contract "${label}" not found. Load it first.`);
    }
    return entry.contract;
  }

  /**
   * Read data from a contract (no gas required)
   */
  async readContract(contractLabel, functionName, ...args) {
    const contract = this.getContract(contractLabel);

    if (typeof contract[functionName] !== 'function') {
      throw new Error(`Function "${functionName}" not found on contract "${contractLabel}"`);
    }

    console.log(`Reading ${contractLabel}.${functionName}(${args.join(', ')})...`);
    const result = await contract[functionName](...args);
    console.log(`Result: ${result}`);
    return result;
  }

  /**
   * Write data to a contract (requires gas and signing)
   */
  async writeContract(contractLabel, functionName, args = [], overrides = {}) {
    const contract = this.getContract(contractLabel);
    const entry = this.contracts.get(contractLabel);

    if (!entry.walletLabel) {
      throw new Error(
        `Contract "${contractLabel}" was loaded without a wallet. ` +
        `Reload it with a wallet label to send transactions.`
      );
    }

    if (typeof contract[functionName] !== 'function') {
      throw new Error(`Function "${functionName}" not found on contract "${contractLabel}"`);
    }

    // Estimate gas
    let gasLimit = overrides.gasLimit;
    if (!gasLimit) {
      try {
        const estimated = await contract[functionName].estimateGas(...args);
        gasLimit = (estimated * 120n) / 100n; // Add 20% buffer
        console.log(`Estimated gas: ${estimated}, Using: ${gasLimit}`);
      } catch (error) {
        console.warn(`Gas estimation failed: ${error.message}. Using default.`);
        gasLimit = CONFIG.GAS_LIMIT_CONTRACT_CALL;
      }
    }

    const txOverrides = {
      gasLimit,
      ...overrides,
    };

    console.log(`Calling ${contractLabel}.${functionName}(${args.join(', ')})...`);
    const txResponse = await contract[functionName](...args, txOverrides);
    console.log(`Transaction sent! Hash: ${txResponse.hash}`);

    const receipt = await txResponse.wait(1);
    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

    // Parse events from the receipt
    const events = receipt.logs.map(log => {
      try {
        return contract.interface.parseLog({ topics: log.topics, data: log.data });
      } catch {
        return null;
      }
    }).filter(Boolean);

    return {
      hash: txResponse.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status === 1 ? 'success' : 'failed',
      events: events.map(e => ({
        name: e.name,
        args: Object.fromEntries(
          Object.entries(e.args).filter(([key]) => isNaN(key))
        ),
      })),
    };
  }

  /**
   * Listen for contract events
   */
  onEvent(contractLabel, eventName, callback) {
    const contract = this.getContract(contractLabel);
    contract.on(eventName, (...args) => {
      const event = args[args.length - 1]; // Last arg is the event object
      console.log(`Event "${eventName}" detected on "${contractLabel}"`);
      callback(...args);
    });
    console.log(`Listening for "${eventName}" events on "${contractLabel}"...`);
  }
}

