// Example ERC-20 Token ABI (minimal)
// ============================================================
const ERC20_ABI = [
  'function name() view returns (string)',
  'function symbol() view returns (string)',
  'function decimals() view returns (uint8)',
  'function totalSupply() view returns (uint256)',
  'function balanceOf(address owner) view returns (uint256)',
  'function transfer(address to, uint256 amount) returns (bool)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function transferFrom(address from, address to, uint256 amount) returns (bool)',
  'event Transfer(address indexed from, address indexed to, uint256 value)',
  'event Approval(address indexed owner, address indexed spender, uint256 value)',
];

// ============================================================
// ERC-20 Token Helper Service
// ============================================================
class TokenService {
  constructor(contractService) {
    this.contractService = contractService;
  }

  loadToken(tokenLabel, tokenAddress, walletLabel) {
    return this.contractService.loadContract(
      tokenLabel, tokenAddress, ERC20_ABI, walletLabel
    );
  }

  async getTokenInfo(tokenLabel) {
    const [name, symbol, decimals, totalSupply] = await Promise.all([
      this.contractService.readContract(tokenLabel, 'name'),
      this.contractService.readContract(tokenLabel, 'symbol'),
      this.contractService.readContract(tokenLabel, 'decimals'),
      this.contractService.readContract(tokenLabel, 'totalSupply'),
    ]);

    return {
      name,
      symbol,
      decimals: Number(decimals),
      totalSupply: ethers.formatUnits(totalSupply, decimals),
    };
  }

  async getBalance(tokenLabel, address) {
    const contract = this.contractService.getContract(tokenLabel);
    const decimals = await contract.decimals();
    const balance = await contract.balanceOf(address);
    return ethers.formatUnits(balance, decimals);
  }

  async transfer(tokenLabel, toAddress, amount) {
    const contract = this.contractService.getContract(tokenLabel);
    const decimals = await contract.decimals();
    const parsedAmount = ethers.parseUnits(amount.toString(), decimals);

    return this.contractService.writeContract(
      tokenLabel, 'transfer', [toAddress, parsedAmount]
    );
  }

  async approve(tokenLabel, spenderAddress, amount) {
    const contract = this.contractService.getContract(tokenLabel);
    const decimals = await contract.decimals();
    const parsedAmount = ethers.parseUnits(amount.toString(), decimals);

    return this.contractService.writeContract(
      tokenLabel, 'approve', [spenderAddress, parsedAmount]
    );
  }
}

// ============================================================
// DApp Backend Service - Main orchestrator
// ============================================================
class DAppBackendService {
  constructor() {
    this.provider = null;
    this.walletManager = null;
    this.transactionService = null;
    this.contractService = null;
    this.tokenService = null;
    this.initialized = false;
  }

  async initialize() {
    console.log('='.repeat(60));
    console.log('Initializing DApp Backend Service...');
    console.log('='.repeat(60));

    // Connect to Ethereum node
    this.provider = new ethers.JsonRpcProvider(CONFIG.RPC_URL);

    // Verify connection
    const network = await this.provider.getNetwork();
    console.log(`Connected to network: ${network.name} (chainId: ${network.chainId})`);

    const blockNumber = await this.provider.getBlockNumber();
    console.log(`Current block number: ${blockNumber}`);

    // Initialize services
    this.walletManager = new WalletManager(this.provider);
    this.transactionService = new TransactionService(this.provider, this.walletManager);
    this.contractService = new ContractService(this.provider, this.walletManager);
    this.tokenService = new TokenService(this.contractService);

    // Load wallets from environment variables
    // Users must set these environment variables before running:
    //   export WALLET_PRIVATE_KEY_MAIN=0x...
    //   export WALLET_PRIVATE_KEY_HOT=0x...
    try {
      this.walletManager.loadWalletFromEnv('WALLET_PRIVATE_KEY_MAIN', 'main');
      console.log('Main wallet loaded successfully.');
    } catch (error) {
      console.warn(`Main wallet not loaded: ${error.message}`);
    }

    try {
      this.walletManager.loadWalletFromEnv('WALLET_PRIVATE_KEY_HOT', 'hot');
      console.log('Hot wallet loaded successfully.');
    } catch (error) {
      console.warn(`Hot wallet not loaded: ${error.message}`);
    }

    this.initialized = true;
    console.log('DApp Backend Service initialized successfully!\n');
    return this;
  }

  ensureInitialized() {
    if (!this.initialized) {
      throw new Error('Service not initialized. Call initialize() first.');
    }
  }

  // ---- ETH Operations ----

  async getWalletBalance(walletLabel) {
    this.ensureInitialized();
    return this.walletManager.getBalance(walletLabel);
  }

  async sendETH(fromWalletLabel, toAddress, amountEther) {
    this.ensureInitialized();
    return this.transactionService.sendETH(fromWalletLabel, toAddress, amountEther);
  }

  async batchSendETH(fromWalletLabel, recipients) {
    this.ensureInitialized();
    return this.transactionService.batchSendETH(fromWalletLabel, recipients);
  }

  // ---- Contract Operations ----

  loadSmartContract(label, address, abi, walletLabel) {
    this.ensureInitialized();
    return this.contractService.loadContract(label, address, abi, walletLabel);
  }

  async readSmartContract(contractLabel, functionName, ...args) {
    this.ensureInitialized();
    return this.contractService.readContract(contractLabel, functionName, ...args);
  }

  async writeSmartContract(contractLabel, functionName, args, overrides) {
    this.ensureInitialized();
    return this.contractService.writeContract(contractLabel, functionName, args, overrides);
  }

  // ---- Token Operations ----

  loadToken(label, address, walletLabel) {
    this.ensureInitialized();
    return this.tokenService.loadToken(label, address, walletLabel);
  }

  async getTokenInfo(tokenLabel) {
    this.ensureInitialized();
    return this.tokenService.getTokenInfo(tokenLabel);
  }

  async getTokenBalance(tokenLabel, address) {
    this.ensureInitialized();
    return this.tokenService.getBalance(tokenLabel, address);
  }

  async transferToken(tokenLabel, toAddress, amount) {
    this.ensureInitialized();
    return this.tokenService.transfer(tokenLabel, toAddress, amount);
  }

  async approveToken(tokenLabel, spenderAddress, amount) {
    this.ensureInitialized();
    return this.tokenService.approve(tokenLabel, spenderAddress, amount);
  }

  // ---- Utility Operations ----

  async getGasPrice() {
    this.ensureInitialized();
    const feeData = await this.provider.getFeeData();
    return {
      gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : null,
      maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei' : null,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei' : null,
    };
  }

  async getTransactionReceipt(txHash) {
    this.ensureInitialized();
    return this.provider.getTransactionReceipt(txHash);
  }

  async waitForTransaction(txHash, confirmations = 1) {
    this.ensureInitialized();
    return this.provider.waitForTransaction(txHash, confirmations);
  }

  async getBlockNumber() {
    this.ensureInitialized();
    return this.provider.getBlockNumber();
  }

  async getBalance(address) {
    this.ensureInitialized();
    const balance = await this.provider.getBalance(address);
    return ethers.formatEther(balance);
  }
}

